import javax.xml.parsers.*;
import org.w3c.dom.*;
import java.io.*;
 
public class XmlParser {
    public static void main(String[] args) throws ParserConfigurationException, IOException{
        String xmlFile = "path_to/yourfile"; // provide your XML file path here  
        
        DocumentBuilderFactory dbFactory = DocumentBuilderFactory.newInstance(); 
        DocumentBuilder dBuilder = dbFactory.newDocumentBuilder();   
         
        try (StreamSource source = new StreamSource(new File(xmlFile))) {    
            parseDocument(dBuilder,source);   //parse the document     
         } catch (ParserConfigurationException | SAXException e) { 
             System.out.println("Error parsing XML: " + xmlFile );   
             
        }      
         
    }//end main method    
          
    private static void parseDocument(DocumentBuilder dBuilder, StreamSource source){   //method to handle the document     
         try { 
             Document doc =dBuilder.parse(source);           
               extractDataFromXmlDocumnet(doc) ;      
          } catch (SAXException e ){   
              System.out.println("Error parsing XML: " + source );   //print error message if any    
         } 
      }//end parseDocument method       
          
             private static void extractDataFromXmlDocumnet( Document doc){       //method to handle the xml document   
                 NodeList nList =doc.getElementsByTagName("*");   //extract all tags from XML    
                  for (int temp = 0;temp <nList.getLength();temp++) { 
                      Node node=nList.item(temp);     
                       if (node instanceof Element){   
                           System.out.println("\nElement : "+node.getNodeName());   //print element name    
                        }         
                  }       
             }//end extractDataFromXmlDocumnet method 
}